#include <stdio.h>
#include <time.h>
#include <assert.h>
#include <stdlib.h> 
#include <math.h> 
#include <sys/time.h>
#include <string.h>

#define STR_SIZE (256)
#define MAX_PD	(3.0e6)
/* required precision in degrees	*/
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
/* capacitance fitting factor	*/
#define FACTOR_CHIP	0.5


/* chip parameters	*/
float t_chip = 0.0005;
float chip_height = 0.016; float chip_width = 0.016; 
/* ambient temperature, assuming no package at all	*/
float amb_temp = 80.0;

void fatal(char *s)
{
    fprintf(stderr, "Error: %s\n", s);
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if( (fp  = fopen(file, "r" )) ==0 )
      fatal( "The file was not opened" );


    for (i=0; i <= grid_rows-1; i++) 
      for (j=0; j <= grid_cols-1; j++)
        for (k=0; k <= layers-1; k++)
          {
            if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (feof(fp))
              fatal("not enough lines in file");
            if ((sscanf(str, "%f", &val) != 1))
              fatal("invalid file format");
            vect[i*grid_cols+j+k*grid_rows*grid_cols] = val;
          }

    fclose(fp);	

}


void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {

    int i,j,k, index=0;
    FILE *fp;
    char str[STR_SIZE];

    if( (fp = fopen(file, "w" )) == 0 )
      printf( "The file was not opened\n" );

    for (i=0; i < grid_rows; i++) 
      for (j=0; j < grid_cols; j++)
        for (k=0; k < layers; k++)
          {
            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j+k*grid_rows*grid_cols]);
            fputs(str,fp);
            index++;
          }

    fclose(fp);	
}



__global__ void computeTempGPU(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, int numiter) 
{  
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int idy = blockIdx.y * blockDim.y + threadIdx.y;
    int idz = blockIdx.z * blockDim.z + threadIdx.z;

    if (idx >= nx || idy >= ny || idz >= nz) return;

    float ce, cw, cn, cs, ct, cb, cc;

    float stepDivCap = dt / Cap;
    ce = cw =stepDivCap/ Rx;
    cn = cs =stepDivCap/ Ry;
    ct = cb =stepDivCap/ Rz;

    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    int c, w, e, n, s, b, t;
    c = idx + idy * nx + idz * nx * ny;
    w = (idx == 0) ? c : c - 1;
    e = (idx == nx - 1) ? c : c + 1;
    n = (idy == 0) ? c : c - nx;
    s = (idy == ny - 1) ? c : c + nx;
    b = (idz == 0) ? c : c - nx * ny;
    t = (idz == nz - 1) ? c : c + nx * ny;

    for (int i = 0; i < numiter; i++) {
        __shared__ float temp[16][16][16];
        if (threadIdx.x < 16 && threadIdx.y < 16 && threadIdx.z < 16) {
            temp[threadIdx.x][threadIdx.y][threadIdx.z] = tIn[c];
        }
        __syncthreads();

        if (idx < nx && idy < ny && idz < nz) {
            tOut[c] = cc * temp[threadIdx.x][threadIdx.y][threadIdx.z] + 
                      cw * ((idx > 0) ? temp[threadIdx.x - 1][threadIdx.y][threadIdx.z] : tIn[w]) + 
                      ce * ((idx < nx - 1) ? temp[threadIdx.x + 1][threadIdx.y][threadIdx.z] : tIn[e]) + 
                      cs * ((idy < ny - 1) ? temp[threadIdx.x][threadIdx.y + 1][threadIdx.z] : tIn[s]) + 
                      cn * ((idy > 0) ? temp[threadIdx.x][threadIdx.y - 1][threadIdx.z] : tIn[n]) + 
                      cb * ((idz > 0) ? temp[threadIdx.x][threadIdx.y][threadIdx.z - 1] : tIn[b]) + 
                      ct * ((idz < nz - 1) ? temp[threadIdx.x][threadIdx.y][threadIdx.z + 1] : tIn[t]) + 
                      (dt / Cap) * pIn[c] + ct * amb_temp;
        }
        __syncthreads();
    }
}

void computeTempGPUWrapper(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, int numiter) 
{  
    int blockSize = 16;
    dim3 block(blockSize, blockSize, blockSize);
    dim3 grid((nx + blockSize - 1) / blockSize, (ny + blockSize - 1) / blockSize, (nz + blockSize - 1) / blockSize);

    float *d_pIn, *d_tIn, *d_tOut;
    cudaMalloc((void **)&d_pIn, nx * ny * nz * sizeof(float));
    cudaMalloc((void **)&d_tIn, nx * ny * nz * sizeof(float));
    cudaMalloc((void **)&d_tOut, nx * ny * nz * sizeof(float));

    cudaMemcpy(d_pIn, pIn, nx * ny * nz * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_tIn, tIn, nx * ny * nz * sizeof(float), cudaMemcpyHostToDevice);

    computeTempGPU<<<grid, block>>>(d_pIn, d_tIn, d_tOut, nx, ny, nz, Cap, Rx, Ry, Rz, dt, numiter);

    cudaMemcpy(tOut, d_tOut, nx * ny * nz * sizeof(float), cudaMemcpyDeviceToHost);

    cudaFree(d_pIn);
    cudaFree(d_tIn);
    cudaFree(d_tOut);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0; 
    int i;
    for(i = 0; i < len; i++)
    {
        err += (arr1[i]-arr2[i]) * (arr1[i]-arr2[i]);
    }

    return (float)sqrt(err/len);
}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <rows/cols> <layers> <iterations> <powerFile> <tempFile> <outputFile>\n", argv[0]);
    fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
    fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");

    fprintf(stderr, "\t<iteration> - number of iterations\n");
    fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
    fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
    fprintf(stderr, "\t<outputFile - output file\n");
    exit(1);
}



int main(int argc, char** argv)
{
    if (argc != 7)
    {
        usage(argc,argv);
    }

    char *pfile, *tfile, *ofile;// *testFile;
    int iterations = atoi(argv[3]);

    pfile = argv[4];
    tfile = argv[5];
    ofile = argv[6];
    //testFile = argv[7];
    int numCols = atoi(argv[1]);
    int numRows = atoi(argv[1]);
    int layers = atoi(argv[2]);

    /* calculating parameters*/

    float dx = chip_height/numRows;
    float dy = chip_width/numCols;
    float dz = t_chip/layers;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
    float Rx = dy / (2.0 * K_SI * t_chip * dx);
    float Ry = dx / (2.0 * K_SI * t_chip * dy);
    float Rz = dz / (K_SI * dx * dy);

    // cout << Rx << " " << Ry << " " << Rz << endl;
    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float dt = PRECISION / max_slope;


    float *powerIn, *tempOut, *tempIn, *tempCopy;// *pCopy;
    //    float *d_powerIn, *d_tempIn, *d_tempOut;
    int size = numCols * numRows * layers;

    powerIn = (float*)calloc(size, sizeof(float));
    tempCopy = (float*)malloc(size * sizeof(float));
    tempIn = (float*)calloc(size,sizeof(float));
    tempOut = (float*)calloc(size, sizeof(float));
    //pCopy = (float*)calloc(size,sizeof(float));
    float* answer = (float*)calloc(size, sizeof(float));

    // outCopy = (float*)calloc(size, sizeof(float));
    readinput(powerIn,numRows, numCols, layers,pfile);
    readinput(tempIn, numRows, numCols, layers, tfile);

    memcpy(tempCopy,tempIn, size * sizeof(float));

    struct timeval start, stop;
    float time;
    gettimeofday(&start,NULL);
    computeTempGPUWrapper(powerIn, tempIn, tempOut, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt,iterations);
    gettimeofday(&stop,NULL);
    time = (stop.tv_usec-start.tv_usec)*1.0e-6 + stop.tv_sec - start.tv_sec;
    computeTempCPU(powerIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt,iterations);

    float acc = accuracy(tempOut,answer,numRows*numCols*layers);
    printf("Time: %.3f (s)\n",time);
    printf("Accuracy: %e\n",acc);
    writeoutput(tempOut,numRows, numCols, layers, ofile);
    free(tempIn);
    free(tempOut); free(powerIn);
    return 0;
}

